package main

import (
	"fmt"
	"log"
	"net/http"
	"os"

	"github.com/gorilla/mux"
)

func main() {
	// Initialize logger
	logger, err := NewLogger("api.log")
	if err != nil {
		log.Fatal(err)
	}
	defer logger.Close()

	// Get server port from environment or default to 8080
	port := os.Getenv("PORT")
	if port == "" {
		port = "8080"
	}

	// Create a new router
	r := mux.NewRouter()

	// Middleware: logging and rate limiting
	r.Use(LoggingMiddleware(logger))
	r.Use(RateLimitMiddleware(10)) // 10 requests per minute

	// Public health check endpoint
	r.HandleFunc("/health", HealthCheckHandler).Methods("GET")

	// Protected routes - require authentication
	protected := r.PathPrefix("/api").Subrouter()
	protected.Use(AuthMiddleware)

	// Admin endpoint (should be protected)
	protected.HandleFunc("/admin", AdminHandler).Methods("GET")

	// User data endpoint (protected)
	protected.HandleFunc("/users", UsersHandler).Methods("GET")

	// Data endpoint (protected)
	protected.HandleFunc("/data", DataHandler).Methods("GET")

	// Start the server
	fmt.Printf("API server initialized\n")
	log.Printf("Server starting on port %s\n", port)
	if err := http.ListenAndServe(":"+port, r); err != nil {
		log.Fatal(err)
	}
}

// HealthCheckHandler returns a simple health status
func HealthCheckHandler(w http.ResponseWriter, r *http.Request) {
	w.WriteHeader(http.StatusOK)
	fmt.Fprintln(w, "OK")
}

// AdminHandler returns admin data (sensitive)
func AdminHandler(w http.ResponseWriter, r *http.Request) {
	w.WriteHeader(http.StatusOK)
	fmt.Fprintln(w, "Sensitive admin data")
}

// UsersHandler returns user data
func UsersHandler(w http.ResponseWriter, r *http.Request) {
	w.WriteHeader(http.StatusOK)
	fmt.Fprintln(w, "[{\"id\":1,\"name\":\"John\"},{\"id\":2,\"name\":\"Jane\"}]")
}

// DataHandler returns some data
func DataHandler(w http.ResponseWriter, r *http.Request) {
	w.WriteHeader(http.StatusOK)
	fmt.Fprintln(w, "Protected data")
}
